import React from 'react';
import './p1.css';
// import Greet from "./navd.js";

import nature from "./assets/nature.jpg"


function App() {
  return (
    <>
    <div className='css1'>


      <div>
        <h1>hello there</h1>
        <p>Name: Navdeep </p>
        <p>Address:Phagwara</p>
        <p>Email:Navdeep7289@gmail.com </p>
        <p>Phone:9870790554</p>
      </div>

      <div className='welcome-image'>
        <img src={nature} alt="" class="img" style={{width: "200px"}}/>
      </div>
      <div className='css2'>
      </div>

    </div>
    <hr />

    <div className='career'>
      <b>Career Ojective</b>
      <p>3rd Year CSE Undergraduation with a focus on full-stack development. Proficient in modern web stacks, Java & C++. Eager to contribute to real-world software projects.
</p>
    </div>

     <div>
<b style={{marginLeft:'220px'}}>Educational Qualification</b>
        <table className="info-table">
        <thead>
          <tr>
            <th>Degree</th>
            <th>Year</th>
